import { useEffect } from 'react';
import { X, Monitor, Sun, Moon, RotateCcw } from 'lucide-react';
import { useTheme } from 'next-themes';
import { cn } from '@/shadcn/lib/utils';
import {
  useAppearance,
  type ColorScheme,
  type FontOption,
  type RadiusOption,
  type DensityOption,
  type ThemeMode,
} from '@/shared/AppearanceContext';

interface Props {
  open: boolean;
  onClose: () => void;
}

const COLOR_SCHEMES: { value: ColorScheme; label: string; color: string }[] = [
  { value: 'orange', label: 'Orange', color: '#e85c0d' },
  { value: 'zinc',   label: 'Zinc',   color: '#71717a' },
  { value: 'blue',   label: 'Blue',   color: '#2563eb' },
  { value: 'green',  label: 'Green',  color: '#16a34a' },
  { value: 'rose',   label: 'Rose',   color: '#e11d48' },
  { value: 'violet', label: 'Violet', color: '#7c3aed' },
];

const FONTS: { value: FontOption; label: string; family: string }[] = [
  { value: 'inter',            label: 'Inter',            family: "'Inter Variable', sans-serif" },
  { value: 'geist',            label: 'Geist',            family: "'Geist Variable', sans-serif" },
  { value: 'jakarta',          label: 'Plus Jakarta Sans', family: "'Plus Jakarta Sans Variable', sans-serif" },
  { value: 'dm-sans',          label: 'DM Sans',          family: "'DM Sans Variable', sans-serif" },
  { value: 'ibm-plex-sans',    label: 'IBM Plex Sans',    family: "'IBM Plex Sans Variable', sans-serif" },
  { value: 'manrope',          label: 'Manrope',          family: "'Manrope Variable', sans-serif" },
  { value: 'source-serif-4',   label: 'Source Serif 4',   family: "'Source Serif 4 Variable', serif" },
  { value: 'jetbrains-mono',   label: 'JetBrains Mono',   family: "'JetBrains Mono Variable', monospace" },
  { value: 'oswald',           label: 'Oswald',           family: "'Oswald Variable', sans-serif" },
];

const RADIUS_OPTIONS: { value: RadiusOption; label: string; previewRadius: string }[] = [
  { value: 'sharp',   label: 'Sharp',   previewRadius: '0px' },
  { value: 'default', label: 'Default', previewRadius: '6px' },
  { value: 'rounded', label: 'Rounded', previewRadius: '10px' },
  { value: 'pill',    label: 'Pill',    previewRadius: '20px' },
];

const DENSITY_OPTIONS: { value: DensityOption; label: string; desc: string }[] = [
  { value: 'compact',     label: 'Compact',     desc: 'Tighter' },
  { value: 'comfortable', label: 'Comfortable', desc: 'Default' },
  { value: 'spacious',    label: 'Spacious',    desc: 'Generous' },
];

const MODE_OPTIONS: { value: ThemeMode; label: string; Icon: React.ElementType }[] = [
  { value: 'system', label: 'System', Icon: Monitor },
  { value: 'light',  label: 'Light',  Icon: Sun },
  { value: 'dark',   label: 'Dark',   Icon: Moon },
];

export function AppearanceSheet({ open, onClose }: Props) {
  const { theme } = useTheme();
  const {
    colorScheme, fontSans, fontHeading, radius, density,
    userTheme, hasUserOverrides,
    setColorScheme, setFontSans, setFontHeading, setRadius, setDensity, setMode,
    resetToDefaults,
  } = useAppearance();

  // Close on Escape
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  // Lock body scroll while open
  useEffect(() => {
    document.body.style.overflow = open ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [open]);

  const handleReset = async () => {
    await resetToDefaults();
  };

  return (
    <>
      {/* Dimming overlay */}
      <div
        onClick={onClose}
        aria-hidden="true"
        className={cn(
          'fixed inset-0 z-40 bg-black/20 transition-opacity duration-300',
          open ? 'pointer-events-auto opacity-100' : 'pointer-events-none opacity-0',
        )}
      />

      {/* Slide-in panel */}
      <div
        role="dialog"
        aria-modal="true"
        aria-label="Appearance settings"
        className={cn(
          'fixed inset-y-0 right-0 z-50 flex w-80 flex-col',
          'bg-card border-l border-border',
          'shadow-[-8px_0_32px_0_rgba(0,0,0,0.18),-2px_0_8px_0_rgba(0,0,0,0.10)]',
          'transition-transform duration-300 ease-[cubic-bezier(0.4,0,0.2,1)]',
          open ? 'translate-x-0' : 'translate-x-full',
        )}
      >
        {/* Header */}
        <div className="flex shrink-0 items-center justify-between border-b border-border px-5 py-4">
          <div>
            <p className="text-sm font-semibold text-foreground">Appearance</p>
            <p className="mt-0.5 text-xs text-muted-foreground">Customize your experience</p>
          </div>
          <button
            onClick={onClose}
            className="flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        {/* Scrollable body */}
        <div className="flex-1 space-y-6 overflow-y-auto p-5">

          {/* ── Color scheme ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.colorScheme != null}>Color</SectionLabel>
            <div className="grid grid-cols-3 gap-2">
              {COLOR_SCHEMES.map(({ value, label, color }) => (
                <button
                  key={value}
                  onClick={() => setColorScheme(value)}
                  className={cn(
                    'flex flex-col items-center gap-1.5 rounded-lg border p-2 transition-all',
                    colorScheme === value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <span
                    className="h-6 w-6 rounded-full shadow-sm ring-2 ring-white/50 dark:ring-black/30"
                    style={{ backgroundColor: color }}
                  />
                  <span className={cn(
                    'text-[10px] font-medium',
                    colorScheme === value ? 'text-primary' : 'text-muted-foreground',
                  )}>
                    {label}
                  </span>
                </button>
              ))}
            </div>
          </section>

          {/* ── Light / Dark / System ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.mode != null}>Theme</SectionLabel>
            <div className="grid grid-cols-3 gap-2">
              {MODE_OPTIONS.map(({ value, label, Icon }) => (
                <button
                  key={value}
                  onClick={() => setMode(value)}
                  className={cn(
                    'flex flex-col items-center gap-1.5 rounded-lg border p-3 transition-all',
                    theme === value
                      ? 'border-primary bg-primary/5 text-primary'
                      : 'border-border text-muted-foreground hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <Icon className="h-4 w-4" />
                  <span className="text-[10px] font-medium">{label}</span>
                </button>
              ))}
            </div>
          </section>

          {/* ── Body Font ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.fontSans != null}>Body Font</SectionLabel>
            <div className="space-y-1.5">
              {FONTS.map(({ value, label, family }) => (
                <button
                  key={value}
                  onClick={() => setFontSans(value)}
                  className={cn(
                    'flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-all',
                    fontSans === value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <span
                    className={cn('text-sm font-medium', fontSans === value ? 'text-primary' : 'text-foreground')}
                    style={{ fontFamily: family }}
                  >
                    {label}
                  </span>
                  <span
                    className="text-lg font-bold text-muted-foreground"
                    style={{ fontFamily: family }}
                  >
                    Aa
                  </span>
                </button>
              ))}
            </div>
          </section>

          {/* ── Heading Font ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.fontHeading != null}>Heading Font</SectionLabel>
            <div className="space-y-1.5">
              {FONTS.map(({ value, label, family }) => (
                <button
                  key={value}
                  onClick={() => setFontHeading(value)}
                  className={cn(
                    'flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-all',
                    fontHeading === value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <span
                    className={cn('text-sm font-medium', fontHeading === value ? 'text-primary' : 'text-foreground')}
                    style={{ fontFamily: family }}
                  >
                    {label}
                  </span>
                  <span
                    className="text-lg font-bold text-muted-foreground"
                    style={{ fontFamily: family }}
                  >
                    Aa
                  </span>
                </button>
              ))}
            </div>
          </section>

          {/* ── Corners / Radius ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.radius != null}>Corners</SectionLabel>
            <div className="grid grid-cols-4 gap-2">
              {RADIUS_OPTIONS.map(({ value, label, previewRadius }) => (
                <button
                  key={value}
                  onClick={() => setRadius(value)}
                  className={cn(
                    'flex flex-col items-center gap-2 rounded-lg border p-2 transition-all',
                    radius === value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <div
                    className={cn('h-7 w-7 border-2', radius === value ? 'border-primary' : 'border-muted-foreground/40')}
                    style={{ borderRadius: previewRadius }}
                  />
                  <span className={cn(
                    'text-[10px] font-medium',
                    radius === value ? 'text-primary' : 'text-muted-foreground',
                  )}>
                    {label}
                  </span>
                </button>
              ))}
            </div>
          </section>

          {/* ── Density ── */}
          <section>
            <SectionLabel hasOverride={userTheme?.density != null}>Density</SectionLabel>
            <div className="space-y-1.5">
              {DENSITY_OPTIONS.map(({ value, label, desc }) => (
                <button
                  key={value}
                  onClick={() => setDensity(value)}
                  className={cn(
                    'flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-all',
                    density === value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-muted-foreground/30 hover:bg-muted',
                  )}
                >
                  <span className={cn('text-sm font-medium', density === value ? 'text-primary' : 'text-foreground')}>
                    {label}
                  </span>
                  <span className="text-xs text-muted-foreground">{desc}</span>
                </button>
              ))}
            </div>
          </section>

        </div>

        {/* Footer — reset button, only visible when user has overrides */}
        {hasUserOverrides && (
          <div className="shrink-0 border-t border-border px-5 py-4">
            <button
              onClick={handleReset}
              className={cn(
                'flex w-full items-center justify-center gap-2 rounded-lg border border-border px-3 py-2.5',
                'text-sm font-medium text-muted-foreground transition-all',
                'hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive',
              )}
            >
              <RotateCcw className="h-3.5 w-3.5" />
              Reset to organization defaults
            </button>
          </div>
        )}
      </div>
    </>
  );
}

function SectionLabel({ children, hasOverride }: { children: React.ReactNode; hasOverride?: boolean }) {
  return (
    <h3 className="mb-3 flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
      {children}
      {hasOverride && (
        <span className="h-1.5 w-1.5 rounded-full bg-primary" title="Customized" />
      )}
    </h3>
  );
}
