import { useEffect, useState } from "react";
import { format } from "date-fns";
import { Calendar, Clock, Palette } from "lucide-react";
import { cn } from "@/shadcn/lib/utils";
import { AppearanceSheet } from "@/components/shared/AppearanceSheet";
import { HarmonyApiStatus } from "@/components/ui/harmony-api-status";
import { SidebarTrigger } from "@/shadcn/components/ui/sidebar";
import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from "@/shadcn/components/ui/hover-card";
import { Calendar as CalendarPicker } from "@/shadcn/components/ui/calendar";
import { Button } from "@/shadcn/components/ui/button";

export default function Header() {
  const [now, setNow] = useState(new Date());
  const [appearanceOpen, setAppearanceOpen] = useState(false);
  const [calendarMonth, setCalendarMonth] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const isCurrentMonth =
    calendarMonth.getMonth() === now.getMonth() &&
    calendarMonth.getFullYear() === now.getFullYear();

  const formattedDate = format(now, "EEE, dd MMM yyyy");
  const formattedTime = format(now, "hh:mm a");

  return (
    <>
      <header className="sticky top-0 z-30 flex h-16 items-center justify-between gap-3 border-b border-border bg-card/95 px-4 shadow-sm">

        <SidebarTrigger className="h-9 w-9 rounded-xl bg-muted text-muted-foreground hover:bg-accent" />

        <div className="flex items-center gap-3">

          <button
            onClick={() => setAppearanceOpen(true)}
            title="Appearance settings"
            className={cn(
              "flex h-9 w-9 items-center justify-center rounded-xl",
              "bg-muted text-muted-foreground transition-colors hover:bg-accent",
            )}
          >
            <Palette className="h-4 w-4" strokeWidth={2.5} />
            <span className="sr-only">Appearance settings</span>
          </button>

          {/* Date & Time widget */}
          <HoverCard openDelay={200} closeDelay={100}>
            <HoverCardTrigger asChild>
              <div
                role="button"
                tabIndex={0}
                title="Open calendar"
                className="flex cursor-pointer select-none items-center gap-5 rounded-2xl border border-border bg-card px-3 py-1 shadow-sm ring-1 ring-black/3 transition-all duration-300 hover:shadow-md dark:ring-white/4"
              >
                <div className="flex items-center gap-3 pl-1">
                  <div className="rounded-lg bg-muted p-1.5">
                    <Calendar className="h-4 w-4 text-muted-foreground" strokeWidth={2.5} />
                  </div>
                  <span className="mt-0.5 text-xs font-bold uppercase tracking-widest text-muted-foreground">
                    {formattedDate}
                  </span>
                </div>

                <div className="h-6 w-0.5 rounded-full bg-border" />

                <div className="flex items-center gap-3 pr-2">
                  <div className="rounded-lg bg-muted p-1.5">
                    <Clock className="h-4 w-4 text-muted-foreground" strokeWidth={2.5} />
                  </div>
                  <span className="mt-0.5 min-w-19 text-xs font-black tabular-nums tracking-tight text-foreground">
                    {formattedTime}
                  </span>
                </div>
              </div>
            </HoverCardTrigger>

            <HoverCardContent align="end" sideOffset={8} className="w-auto p-0 overflow-hidden">
              <CalendarPicker
                mode="single"
                selected={today}
                month={calendarMonth}
                onMonthChange={setCalendarMonth}
              />
              <div className="border-t border-border px-3 pb-3 pt-2">
                <Button
                  variant="outline"
                  size="sm"
                  className="w-full"
                  disabled={isCurrentMonth}
                  onClick={() => setCalendarMonth(new Date())}
                >
                  Today
                </Button>
              </div>
            </HoverCardContent>
          </HoverCard>

          <HarmonyApiStatus />

        </div>
      </header>

      <AppearanceSheet open={appearanceOpen} onClose={() => setAppearanceOpen(false)} />
    </>
  );
}
