import { Outlet } from "react-router-dom";
import AppSidebar from "./Sidebar";
import Header from "./Header";
import { SidebarProvider } from "@/shadcn/components/ui/sidebar";

export default function MainLayout() {
  const saved = document.cookie.split("; ").find(r => r.startsWith("sidebar_state="))?.split("=")[1];
  const defaultOpen = saved !== "false";

  return (
    <SidebarProvider
      defaultOpen={defaultOpen}
      className="h-screen overflow-hidden bg-background text-foreground selection:bg-primary/20 selection:text-primary"
    >
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full" style={{ background: 'radial-gradient(circle, oklch(from var(--primary) l c h / 0.07) 0%, transparent 70%)' }} />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full" style={{ background: 'radial-gradient(circle, oklch(from var(--primary) l c h / 0.07) 0%, transparent 70%)' }} />
      </div>

      <AppSidebar />

      <div className="flex-1 flex flex-col min-w-0 relative z-10 overflow-hidden">
        <Header />
        <main className="flex-1 overflow-auto no-scrollbar">
          <Outlet />
        </main>
      </div>
    </SidebarProvider>
  );
}
