import { Fragment } from "react";
import { NavLink, useLocation } from "react-router-dom";
import {
    Home,
    Users,
    Calendar,
    CalendarDays,
    Settings,
    LayoutGrid,
    LogOut,
    ShieldCheck,
    Briefcase,
    ScanSearch,
    KeyRound,
    PartyPopper,
    ScrollText,
    CalendarX,
    ClipboardCheck,
} from "lucide-react";
import { useAuth } from "@/shared/AuthContext";
import { UserAvatar } from "@/components/ui/UserAvatar";
import { useAuditMode } from "@/shared/AuditModeContext";
import { PERMISSIONS } from "@/constants/permissions";
import { cn } from "@/shadcn/lib/utils";
import {
    Sidebar,
    SidebarContent,
    SidebarFooter,
    SidebarGroup,
    SidebarGroupContent,
    SidebarGroupLabel,
    SidebarHeader,
    SidebarMenu,
    SidebarMenuButton,
    SidebarMenuItem,
    SidebarRail,
    SidebarSeparator,
} from "@/shadcn/components/ui/sidebar";

type MenuItem = {
    icon: React.ComponentType<React.SVGProps<SVGSVGElement>>;
    label: string;
    path: string;
    permission?: string;
};

type MenuGroup = {
    label?: string;
    items: MenuItem[];
};

const menuGroups: MenuGroup[] = [
    {
        items: [
            { icon: Home, label: "Dashboard", path: "/dashboard" },
        ],
    },
    {
        label: "People & Access",
        items: [
            { icon: Users,       label: "Manage Users",        path: "/users",          permission: PERMISSIONS.Employee.Read },
            { icon: ShieldCheck, label: "Roles & Permissions", path: "/roles",          permission: PERMISSIONS.Role.Read },
            { icon: KeyRound,    label: "My Permissions",      path: "/my-permissions" },
        ],
    },
    {
        label: "Work Schedules",
        items: [
            { icon: CalendarDays,   label: "My Schedule",        path: "/my-work-schedule" },
            { icon: Calendar,       label: "Team Schedule",       path: "/team-schedule",            permission: PERMISSIONS.WorkSchedule.Read },
            { icon: ClipboardCheck, label: "Approvals",           path: "/team-schedule-approval",   permission: PERMISSIONS.WorkSchedule.Approve },
        ],
    },
    {
        label: "Time & Leave",
        items: [
            { icon: CalendarX,   label: "Leave Management", path: "/leave-management", permission: PERMISSIONS.Leave.Read },
            { icon: PartyPopper, label: "Public Holidays",  path: "/public-holidays" },
        ],
    },
    {
        label: "Business",
        items: [
            { icon: Briefcase,  label: "Customers",   path: "/customers",   permission: PERMISSIONS.Customer.Read },
            { icon: LayoutGrid, label: "Assignments", path: "/assignments", permission: PERMISSIONS.ProjectAssignment.Read },
        ],
    },
    {
        label: "System",
        items: [
            { icon: Settings,   label: "Settings",    path: "/application-settings", permission: PERMISSIONS.ApplicationSettings.Read },
            { icon: ScrollText, label: "System Logs", path: "/logs",                 permission: PERMISSIONS.ApplicationSettings.Read },
        ],
    },
];

function NavItem({ item }: { item: MenuItem }) {
    const location = useLocation();
    const isActive = location.pathname.startsWith(item.path);

    return (
        <SidebarMenuItem>
            <SidebarMenuButton asChild isActive={isActive} tooltip={item.label} className="rounded-2xl">
                <NavLink to={item.path}>
                    <item.icon />
                    <span>{item.label}</span>
                </NavLink>
            </SidebarMenuButton>
        </SidebarMenuItem>
    );
}

export default function AppSidebar() {
    const { user, logout, hasPermission, profilePictureVersion } = useAuth();
    const { isAuditMode, toggleAuditMode } = useAuditMode();
    const { pathname } = useLocation();
    const isDev = import.meta.env.DEV;

    const filteredGroups = menuGroups
        .map(group => ({
            ...group,
            items: group.items.filter(item => !item.permission || hasPermission(item.permission)),
        }))
        .filter(group => group.items.length > 0);

    return (
        <Sidebar collapsible="icon">
            <SidebarHeader>
                <SidebarMenu className="group-data-[state=collapsed]:py-1.75 transition-[padding] duration-200 ease-linear">
                    <SidebarMenuItem>
                        <SidebarMenuButton size="lg" asChild className="rounded-2xl h-14">
                            <NavLink to="/">
                                <div className="flex aspect-square size-11 group-data-[collapsible=icon]:size-8 shrink-0 items-center justify-center rounded-xl group-data-[collapsible=icon]:rounded-full bg-slate-900 border border-white/10 ring-1 ring-slate-300 ring-offset-2 shadow-lg dark:bg-slate-200 dark:border-slate-300/50 dark:ring-slate-700 dark:shadow-xl group-data-[collapsible=icon]:ring-0 transition-all duration-200 ease-linear">
                                    <img src="/images/logo.png" alt="Harmony" className="size-7 group-data-[collapsible=icon]:size-5 object-contain transition-all duration-200 ease-linear" />
                                </div>
                                <span className="font-black text-xl tracking-wide text-sidebar-foreground leading-none uppercase transition-opacity duration-200 ease-linear group-data-[collapsible=icon]:opacity-0 group-data-[collapsible=icon]:duration-75 group-data-[collapsible=icon]:delay-150">
                                    Harmony
                                </span>
                            </NavLink>
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                </SidebarMenu>
            </SidebarHeader>

            <SidebarContent className="py-2 overflow-x-hidden">
                {filteredGroups.map((group, index) => (
                    <Fragment key={group.label ?? "__main__"}>
                        {index > 0 && <SidebarSeparator />}
                        <SidebarGroup>
                            {group.label && (
                                <SidebarGroupLabel className="text-[10px] font-bold uppercase tracking-widest text-sidebar-foreground/40 px-2 mb-0.5">
                                    {group.label}
                                </SidebarGroupLabel>
                            )}
                            <SidebarGroupContent>
                                <SidebarMenu>
                                    {group.items.map(item => (
                                        <NavItem key={item.path} item={item} />
                                    ))}
                                </SidebarMenu>
                            </SidebarGroupContent>
                        </SidebarGroup>
                    </Fragment>
                ))}
            </SidebarContent>

            <SidebarFooter className="border-t border-sidebar-border p-3">
                <SidebarMenu>
                    <SidebarMenuItem>
                        <SidebarMenuButton
                            asChild
                            isActive={pathname === "/my-profile"}
                            size="lg"
                            tooltip={[user?.firstName, user?.lastName].filter(Boolean).join(" ") || "Profile"}
                            className="rounded-2xl h-auto py-1.5 group-data-[collapsible=icon]:justify-center"
                        >
                            <NavLink to="/my-profile">
                                <UserAvatar
                                    userId={user?.id}
                                    firstName={user?.firstName}
                                    lastName={user?.lastName}
                                    cacheKey={profilePictureVersion}
                                    className="size-12 shrink-0 rounded-2xl group-data-[collapsible=icon]:size-8 group-data-[collapsible=icon]:rounded-full transition-all duration-200 ease-linear"
                                />
                                <span className="font-bold">
                                    {[user?.firstName, user?.lastName].filter(Boolean).join(" ") || user?.email?.split("@")[0] || "Guest"}
                                </span>
                            </NavLink>
                        </SidebarMenuButton>
                    </SidebarMenuItem>

                    {isDev && (
                        <SidebarMenuItem>
                            <SidebarMenuButton
                                onClick={toggleAuditMode}
                                tooltip={isAuditMode ? "Audit Mode: ON" : "Audit Mode"}
                                className={cn(
                                    "rounded-2xl",
                                    isAuditMode
                                        ? "text-warning bg-warning/10 border border-warning/20 hover:bg-warning/15"
                                        : "text-sidebar-foreground/50 hover:text-sidebar-foreground hover:bg-sidebar-accent"
                                )}
                            >
                                <ScanSearch className="size-4 shrink-0" />
                                <span>Audit Mode</span>
                                {isAuditMode && (
                                    <span className="ml-auto size-1.5 rounded-full bg-warning animate-pulse" />
                                )}
                            </SidebarMenuButton>
                        </SidebarMenuItem>
                    )}

                    <SidebarMenuItem>
                        <SidebarMenuButton
                            onClick={logout}
                            tooltip="Sign Out"
                            className="rounded-2xl text-sidebar-foreground/80 hover:text-rose-400 hover:bg-rose-500/10"
                        >
                            <LogOut className="size-4" />
                            <span>Sign Out</span>
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                </SidebarMenu>
            </SidebarFooter>

            <SidebarRail />
        </Sidebar>
    );
}
